mapper.select:
SELECT d.*, u.username, u.phone as user_phone, e.name as equipment_name, CASE d.deduction_type WHEN 'damage' THEN '设备损坏' WHEN 'overdue' THEN '逾期归还' END as deduction_type_text, CASE d.damage_level WHEN 'light' THEN '轻微' WHEN 'moderate' THEN '中度' WHEN 'severe' THEN '严重' END as damage_level_text, CASE d.status WHEN 'pending' THEN '待处理' WHEN 'approved' THEN '已批准' WHEN 'rejected' THEN '已拒绝' END as status_text FROM db_deposit_deduction d LEFT JOIN db_account u ON d.user_id = u.id LEFT JOIN db_equipment e ON d.equipment_id = e.id
1=1
AND d.user_id = #{userId}
AND d.status = #{status}
ORDER BY d.create_time DESC
